result:
.hero{
  padding: 0px !important;
  margin:0px !important;
  .title{

    font-family: "Space Mono";
    padding:0px;
    font-weight:bold;

    .unit{
      text-align:center;
      display:inline-block;
      width:100px;
      height:172px;
      position:relative;
      .letter{
        line-height:150px;
         font-size:140px;
        margin:auto;
        left:0px;
        right:0px;
        opacity:1;
        position:absolute;
        top:0px;

      }
      .fas{
        position:absolute;
        top:0px;
        margin:auto;
        left:0px;
        right:0px;
        line-height:172px;
        font-size:80px;
        overflow-y:hidden;
        height:200px;
        opacity:0;
        color: $magenta;
      }
    }
    .unit:hover, .unit.active{

      .letter{
        opacity:0;
      }
      .fas{
        opacity:1;

      }
    }

     .unit:hover:not(.active){
      cursor:pointer;
      .fas{
        color: black;
      }
     }


     .unit:click{
      .fas{
        font-size:64px;
      }
     }


  }
  .hero-text{
    font-weight:normal;
    font-size:38px;
    margin:0px;
    padding:0px;
  }

}
#work{
  .see-all-projects{
    padding-top:40px;
  }
}

#contact{
  padding:0px;


  .social-link {
    a, .far, .fab {
      display:inline-block;
      vertical-align:middle;
    }

    .far, .fab{
    font-size:32px;
    margin-right:24px;
    color: $magenta;
/*    background-color:yellow;*/
    /*border-radius:100px;*/
    padding-right:16px;
    mix-blend-mode: multiply;


    }

    h3{
      margin:0px;
      color:black;
    }
    p{
      margin:8px 0px 0px 0px;
    }
  } 



}


 @keyframes giggle {
   0%, 100% {
      transform:translate(-50%,-50%) translateY(-3px);
   }
   50% {
      transform:translate(-50%,-50%) translateY(3px);
   }
}

 @keyframes giggleB {
   0%, 100% {
      transform:translate(-50%,-50%) translateY(-6px);
   }
   50% {
      transform:translate(-50%,-50%) translateY(6px);
   }
}
@keyframes lines {
   0% {
      background-position:0px 0px;
   }
   100% {
      background-position:0px 25px;
   }
}



.bg-container{

  width:100vw;
  position:absolute;
  left:0px;
  top:0px;
  height:1400px;
  overflow-x:hidden;
  z-index:-100;


  .fas, .far{
    position:absolute;
    mix-blend-mode:darken;
    /*opacity:.5;*/
     animation:  giggle 1.6s ease infinite;
     z-index:-100;
  }

  .magenta{
    color:$magenta;
  }
  .yellow{
    color:$yellow;
  }
  .cyan{
    color:$cyan;
  }
  .x-small{
    font-size:14px;
  }
  .small{
    font-size:20px;
  }
  .med{
    font-size:60px;
  }
  .large{
    font-size:100px;
  }

  .x-large{
    font-size:180px;
  }

}

.bg-symbol{
  position:relative;
  z-index:-100;

  i {
    position:absolute;
    top:0px;
    left:0px;
    font-size:300px;
     mix-blend-mode: difference;

  }
}


.hero-arrow{
      font-size: 48px;
      position:relative;
      top:40px;
/*      left: calc( 50% - 8px);*/
     /* left: 50%;
      right: 50%;*/
/*      top: 630px;
      position: absolute;*/
      opacity:0;
      transition: .6s opacity;
}
